import{c as e,Q as t,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"关于本书","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1779804559000}'),l={name:"about.md"};function n(i,a,s,h,u,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="关于本书" tabindex="-1">关于本书 <a class="header-anchor" href="#关于本书" aria-label="Permalink to &quot;关于本书&quot;">​</a></h1><h2 id="这本书是什么" tabindex="-1">这本书是什么 <a class="header-anchor" href="#这本书是什么" aria-label="Permalink to &quot;这本书是什么&quot;">​</a></h2><p>《如何从零构建 7×24 小时 AI Agent》是一本讲 AI Agent 系统设计思想的技术书。从问题出发,教设计原则,用 30 万行真实代码做案例。</p><p>本书用 Halo(30 万行 TypeScript,开源 AI Agent 平台)作为贯穿全书的案例,讲 AI Agent 系统从引擎到调度到浏览器自动化的设计思想。你读完能拿走的不是&quot;Halo 的代码怎么写的&quot;,而是&quot;我的项目遇到类似问题时该怎么想&quot;。</p><h2 id="适合谁读" tabindex="-1">适合谁读 <a class="header-anchor" href="#适合谁读" aria-label="Permalink to &quot;适合谁读&quot;">​</a></h2><ul><li><strong>想理解 AI Agent 系统设计的开发者</strong>:你有 1-3 年经验,能写业务代码,但没机会接触大型系统的架构决策</li><li><strong>正在构建 AI 工具但卡在&quot;从能用到好用&quot;的独立开发者</strong>:启动越来越慢、模块依赖混乱、多平台维护成本高——这些工程问题的设计思路,本书每一章都在讲</li><li><strong>好奇&quot;一个人加 AI 能做到什么程度&quot;的人</strong>:第十三章,方法论,不是鸡汤</li></ul><h2 id="不适合谁读" tabindex="-1">不适合谁读 <a class="header-anchor" href="#不适合谁读" aria-label="Permalink to &quot;不适合谁读&quot;">​</a></h2><ul><li>想了解&quot;AI 是什么&quot;的入门者(市面上有更好的书)</li><li>想看通用 LLM 原理(自注意力、MoE 等)的人</li></ul><h2 id="作者" tabindex="-1">作者 <a class="header-anchor" href="#作者" aria-label="Permalink to &quot;作者&quot;">​</a></h2><p>Flynn,全栈工程师,前腾讯文档高级工程师,2024 年率先落地国产通用 Agent,持有多项 AI 专利,Halo 项目作者。</p><h2 id="协议" tabindex="-1">协议 <a class="header-anchor" href="#协议" aria-label="Permalink to &quot;协议&quot;">​</a></h2><p>本书采用 <a href="https://creativecommons.org/licenses/by-nc-nd/4.0/deed.zh" target="_blank" rel="noreferrer">CC BY-NC-ND 4.0</a> 协议授权:</p><ul><li>✅ 允许:分享、传播、引用</li><li>❌ 禁止:商业使用、修改后传播</li></ul><h2 id="反馈与勘误" tabindex="-1">反馈与勘误 <a class="header-anchor" href="#反馈与勘误" aria-label="Permalink to &quot;反馈与勘误&quot;">​</a></h2><ul><li><strong>勘误 / 建议 / 提问</strong>:<a href="https://github.com/openkursar-flynn/build-ai-agent-platform/issues" target="_blank" rel="noreferrer">https://github.com/openkursar-flynn/build-ai-agent-platform/issues</a></li><li><strong>自由讨论</strong>:<a href="https://github.com/openkursar-flynn/build-ai-agent-platform/discussions" target="_blank" rel="noreferrer">https://github.com/openkursar-flynn/build-ai-agent-platform/discussions</a></li></ul><p>任何错别字、技术错误、章节建议、对内容的疑问,都欢迎提交。</p><h2 id="参考源码" tabindex="-1">参考源码 <a class="header-anchor" href="#参考源码" aria-label="Permalink to &quot;参考源码&quot;">​</a></h2><p>本书拆解的项目 Halo 已完整开源:</p><p><a href="https://github.com/openkursar/hello-halo" target="_blank" rel="noreferrer">https://github.com/openkursar/hello-halo</a></p><p>书中所有源码引用、架构讨论、设计决策均可在该仓库中验证。<code>git clone</code> 后对照阅读效果最佳。</p><h2 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h2><p>感谢所有在 Halo 项目过程中给过反馈、提过 Issue、参与过讨论的人。</p>',22)])])}const b=e(l,[["render",n]]);export{c as __pageData,b as default};
